class Solution:
    def mirrorDistance(self, n: int) -> int:
        digits = []
        x = n
        while x > 0:
            digits.append(x % 10)
            x //= 10
        reversed_n = 0
        for d in digits:
            reversed_n = reversed_n * 10 + d
        return abs(n - reversed_n)

